const trigger = $('Recibir mensaje').first().json;
const mensaje = trigger.message.text.trim();
const chat_id = trigger.message.chat.id;
const telegram_user = String(trigger.message.from.id);

const sd = $getWorkflowStaticData('global');
if (!sd[telegram_user]) {
  sd[telegram_user] = { estado: 'MENU', datos: {} };
}
const session = sd[telegram_user];

return [{
  json: {
    estado: session.estado,
    mensaje: mensaje,
    datos: session.datos,
    chat_id: chat_id,
    telegram_user: telegram_user
  }
}];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;
const mensaje = $json.mensaje;

const tipos = {
  '1': 'Soporte técnico',
  '2': 'Solicitud administrativa',
  '3': 'Consulta general'
};

if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
const session = sd[telegram_user];
session.datos = session.datos || {};
session.datos.tipo = tipos[mensaje];
session.estado = 'PRIORIDAD';

return [{
  json: {
    estado: session.estado,
    datos: session.datos,
    chat_id: $json.chat_id,
    telegram_user: telegram_user,
    mensaje: ` Tipo seleccionado: *${session.datos.tipo}*`
  }
}];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;
const mensaje = $json.mensaje;

const prioridades = { '1': 'Alta', '2': 'Media', '3': 'Baja' };

if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
const session = sd[telegram_user];

if (mensaje === '9') {
  session.estado = 'MENU'; session.datos = {};
  return [{ json: { estado: session.estado, datos: {}, chat_id: $json.chat_id,
    telegram_user, cancelado: 'true', invalido: 'false',
    mensaje: ' Solicitud cancelada. Volviendo al men\u00fa principal.' } }];
}

if (!prioridades[mensaje]) {
  return [{ json: { estado: session.estado, datos: session.datos, chat_id: $json.chat_id,
    telegram_user, cancelado: 'false', invalido: 'true',
    mensaje: ' Opci\u00f3n no v\u00e1lida. Por favor escribe 1, 2, 3 o 9 para cancelar.' } }];
}

session.datos = session.datos || {};
session.datos.prioridad = prioridades[mensaje];
session.estado = 'DESCRIPCION';

return [{ json: { estado: session.estado, datos: session.datos, chat_id: $json.chat_id,
  telegram_user, cancelado: 'false', invalido: 'false',
  mensaje: ` Prioridad seleccionada: *${session.datos.prioridad}*` } }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;
const mensaje = $json.mensaje;

if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
const session = sd[telegram_user];

if (mensaje === '9') {
  session.estado = 'MENU'; session.datos = {};
  return [{ json: { estado: session.estado, datos: {}, chat_id: $json.chat_id,
    telegram_user, cancelado: 'true', invalido: 'false',
    mensaje: ' Solicitud cancelada\\\\. Volviendo al men\u00fa principal\\\\.' } }];
}

if (!mensaje || mensaje.trim().length < 5) {
  return [{ json: { estado: session.estado, datos: session.datos, chat_id: $json.chat_id,
    telegram_user, cancelado: 'false', invalido: 'true',
    mensaje: ' La descripci\u00f3n es muy corta\\\\. Por favor s\u00e9 m\u00e1s espec\u00edfico\\\\.' } }];
}

session.datos = session.datos || {};
session.datos.descripcion = mensaje.trim();
session.estado = 'CONFIRMACION';

return [{ json: { estado: session.estado, datos: session.datos, chat_id: $json.chat_id,
  telegram_user, cancelado: 'false', invalido: 'false',
  mensaje: ' Descripci\u00f3n registrada\\\\.' } }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $('Leer sesión').first().json.telegram_user;
sd[telegram_user] = { estado: 'MENU', datos: {} };
return [{ json: {
  chat_id: $('Leer sesión').first().json.chat_id,
  telegram_user: telegram_user
} }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;

if (sd[telegram_user]) { sd[telegram_user] = { estado: 'MENU', datos: {} }; }

return [{ json: {
  chat_id: $json.chat_id,
  telegram_user: telegram_user,
  mensaje: ' Solicitud cancelada. Volviendo al men\u00fa principal.'
} }];

const chat_id = $('Leer sesión').first().json.chat_id;
const items = $input.all().filter(i => i.json.estado !== 'Cerrado');
if (!items || items.length === 0) {
  return [{ json: { chat_id: chat_id,
    mensaje: '📭 No tienes solicitudes abiertas en este momento.\n\n↩️ Volviendo al menú principal...' } }];
}
let texto = '📋 <b>Tus solicitudes activas:</b>\n\n';
for (const item of items) {
  const t = item.json;
  texto += `🎫 <b>ID:</b> ${t.id_ticket}\n`;
  texto += `📁 <b>Tipo:</b> ${t.tipo}\n`;
  texto += `🔥 <b>Prioridad:</b> ${t.prioridad}\n`;
  texto += `📌 <b>Estado:</b> ${t.estado}\n`;
  texto += `📅 <b>Fecha:</b> ${t.fecha_creacion}\n\n`;
}
texto += '↩️ Volviendo al menú principal...';
return [{ json: { chat_id: chat_id, mensaje: texto } }];

const items = $input.all();
const chat_id = $('Leer sesión').first().json.chat_id;
if (!items || items.length === 0) {
  return [{ json: { chat_id: chat_id,
    mensaje: '📭 Aún no tienes solicitudes registradas.\n\n↩️ Volviendo al menú principal...' } }];
}
let texto = `📋 <b>Todas tus solicitudes:</b> ${items.length} en total\n\n`;
for (const item of items) {
  const t = item.json;
  const estadoEmoji = {'Abierto':'🟢','En proceso':'🟡','Cerrado':'🔴'}[t.estado] || '⚪';
  texto += `🎫 <b>ID:</b> ${t.id_ticket}\n`;
  texto += `📁 <b>Tipo:</b> ${t.tipo}\n`;
  texto += `🔥 <b>Prioridad:</b> ${t.prioridad}\n`;
  texto += `${estadoEmoji} <b>Estado:</b> ${t.estado}\n`;
  texto += `📅 <b>Fecha:</b> ${t.fecha_creacion}\n\n`;
}
texto += '↩️ Volviendo al menú principal...';
return [{ json: { chat_id: chat_id, mensaje: texto } }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;

if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
sd[telegram_user].estado = 'TIPO';
sd[telegram_user].datos = {};

return [{ json: {
  chat_id: $json.chat_id,
  telegram_user: telegram_user,
  estado: 'TIPO',
  datos: {}
} }];

const chat_id = $('Leer sesión').first().json.chat_id;
const items = $input.all();
const counts = { 'Abierto': 0, 'En proceso': 0, 'Cerrado': 0 };
let total = items.length;
if (items.length === 1 && !items[0].json.id_ticket) total = 0;
if (total === 0) {
  return [{ json: { chat_id,
    mensaje: '📊 <b>Reporte de solicitudes</b>\n\nAún no tienes solicitudes registradas.\n\n↩️ Volviendo al menú principal...' } }];
}
for (const item of items) {
  const e = item.json.estado;
  if (counts[e] !== undefined) counts[e]++;
}
const texto =
  '📊 <b>Reporte de tus solicitudes</b>\n\n' +
  `📁 Total: <b>${total}</b>\n\n` +
  `🟢 Abiertos: <b>${counts['Abierto']}</b>\n` +
  `🟡 En proceso: <b>${counts['En proceso']}</b>\n` +
  `🔴 Cerrados: <b>${counts['Cerrado']}</b>\n\n` +
  '↩️ Volviendo al menú principal...';
return [{ json: { chat_id, mensaje: texto } }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $('Leer sesión').first().json.telegram_user;
const chat_id = $('Leer sesión').first().json.chat_id;
if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
sd[telegram_user].estado = 'CONFIG';
sd[telegram_user].datos = {};
const perfil = $input.first().json;
return [{ json: { chat_id, telegram_user,
  nombre: perfil.nombre || 'Sin nombre',
  rol: perfil.rol || 'usuario' } }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;
if (sd[telegram_user]) { sd[telegram_user].estado = 'MENU'; sd[telegram_user].datos = {}; }
return [{ json: { chat_id: $json.chat_id, telegram_user } }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;
if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
sd[telegram_user].estado = 'CONFIG_NOMBRE';
return [{ json: { chat_id: $json.chat_id, telegram_user } }];

const sd = $getWorkflowStaticData('global');
const telegram_user = $json.telegram_user;
const mensaje = $json.mensaje;

if (!sd[telegram_user]) sd[telegram_user] = { estado: 'MENU', datos: {} };
const session = sd[telegram_user];

if (mensaje === '0') {
  session.estado = 'MENU'; session.datos = {};
  return [{ json: { chat_id: $json.chat_id, telegram_user,
    cancelado: 'true', invalido: 'false', datos: {},
    mensaje: 'Operacion cancelada.' } }];
}

if (!mensaje || mensaje.trim().length < 3) {
  return [{ json: { chat_id: $json.chat_id, telegram_user,
    cancelado: 'false', invalido: 'true', datos: session.datos,
    mensaje: 'El nombre es muy corto. Minimo 3 caracteres o escribe 0 para cancelar.' } }];
}

session.datos.nombre_nuevo = mensaje.trim();
session.estado = 'MENU';

return [{ json: { chat_id: $json.chat_id, telegram_user,
  cancelado: 'false', invalido: 'false', datos: session.datos,
  mensaje: 'Nombre actualizado a <b>' + session.datos.nombre_nuevo + '</b>.' } }];
